// ─── Friends ──────────────────────────────────────────────────────────────────

export async function listMyFriends(): Promise<UserProfile[]> {
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return []

  const { data: friendships, error } = await db
    .from('friendships')
    .select('*')
    .or(`user_a_id.eq.${user.id},user_b_id.eq.${user.id}`)

  throwOnError(error, 'listMyFriends')
  if (!friendships?.length) return []

  const friendIds = (friendships as { user_a_id: string; user_b_id: string }[]).map((f) =>
    f.user_a_id === user.id ? f.user_b_id : f.user_a_id
  )

  const { data: profiles, error: pErr } = await db
    .from('user_profiles')
    .select('*')
    .in('user_id', friendIds)

  throwOnError(pErr, 'listMyFriends (profiles)')
  return ((profiles ?? []) as DbUserProfile[]).map(dbProfileToProfile)
}

export async function listMutualFriends(otherUserId: string): Promise<UserProfile[]> {
  // TODO (F5): implement server-side via Supabase RPC for efficiency.
  // Stub: fetch both friend lists and intersect in the app layer.
  const [myFriends, theirProfiles] = await Promise.all([
    listMyFriends(),
    (async () => {
      const { data: fs, error } = await db
        .from('friendships')
        .select('*')
        .or(`user_a_id.eq.${otherUserId},user_b_id.eq.${otherUserId}`)

      if (error) return []
      const ids = ((fs ?? []) as { user_a_id: string; user_b_id: string }[]).map((f) =>
        f.user_a_id === otherUserId ? f.user_b_id : f.user_a_id
      )
      if (!ids.length) return []

      const { data: profiles } = await db
        .from('user_profiles')
        .select('*')
        .in('user_id', ids)

      return ((profiles ?? []) as DbUserProfile[]).map(dbProfileToProfile)
    })(),
  ])

  const myFriendIds = new Set(myFriends.map((p) => p.userId))
  return theirProfiles.filter((p) => myFriendIds.has(p.userId))
}

export async function removeFriend(friendUserId: string): Promise<void> {
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) throw new Error('[friendsStore] removeFriend: not authenticated')

  const userA = user.id < friendUserId ? user.id : friendUserId
  const userB = user.id < friendUserId ? friendUserId : user.id

  const { error } = await db
    .from('friendships')
    .delete()
    .eq('user_a_id', userA)
    .eq('user_b_id', userB)

  throwOnError(error, 'removeFriend')
}

export async function areFriends(otherUserId: string): Promise<boolean> {
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return false

  const userA = user.id < otherUserId ? user.id : otherUserId
  const userB = user.id < otherUserId ? otherUserId : user.id

  const { data, error } = await db
    .from('friendships')
    .select('id')
    .eq('user_a_id', userA)
    .eq('user_b_id', userB)
    .maybeSingle()

  throwOnError(error, 'areFriends')
  return data !== null
}

