export async function tagUser(gameId: string, taggedUserId: string): Promise<GameTag> {
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) throw new Error('[friendsStore] tagUser: not authenticated')

  // TODO (F8): notify the tagged user
  const { data, error } = await db
    .from('game_tags')
    .insert({ game_id: gameId, tagged_user_id: taggedUserId, tagged_by_user_id: user.id })
    .select()
    .single()

  throwOnError(error, 'tagUser')
  return dbGameTagToGameTag(data as DbGameTag)
}

export async function removeTag(gameId: string, taggedUserId: string): Promise<void> {
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) throw new Error('[friendsStore] removeTag: not authenticated')

  if (taggedUserId === user.id) {
    // Tagged user removes themselves — set flag rather than delete row.
    const { error } = await db
      .from('game_tags')
      .update({ removed_by_tagged_user: true })
      .eq('game_id', gameId)
      .eq('tagged_user_id', user.id)
    throwOnError(error, 'removeTag (self)')
  } else {
    // Game owner deletes the tag row entirely.
    const { error } = await db
      .from('game_tags')
      .delete()
      .eq('game_id', gameId)
      .eq('tagged_user_id', taggedUserId)
    throwOnError(error, 'removeTag (owner)')
  }
}

export async function listTags(gameId: string): Promise<GameTag[]> {
  const { data, error } = await db
    .from('game_tags')
    .select('*')
    .eq('game_id', gameId)
    .eq('removed_by_tagged_user', false)

  throwOnError(error, 'listTags')
  return ((data ?? []) as DbGameTag[]).map(dbGameTagToGameTag)
}

